 elements.addAppForm.addEventListener("submit", async (event) => {
   event.preventDefault();
   const payload = Object.fromEntries(
@@ -384,4 +562,7 @@ elements.addAppForm.addEventListener("submit", async (event) => {
   await loadApps();
 });

